# Decorative Emojis to REMOVE (strip them to keep it clean)
REMOVE_LIST = [
    "🚀", "💡", "📚", "🌐", "🎞️", "🎯", "🖥️", "📖", "🔍", "🕵️", "⚙️", "🛠️", "🚨", "📺", "📷", "🔄", "📉", "🔮",
    "📼", "🟢", "🔧", "🔗", "🎉", "🏆", "🌙", "☀", "⚠️", "✅" 
]

def update_files():
    files = [f for f in os.listdir(DOCS_DIR) if f.endswith(".html")]
    print(f"Processing {len(files)} files in {DOCS_DIR}")
    
    for filename in files:
        path = os.path.join(DOCS_DIR, filename)
        with open(path, "r", encoding="utf-8") as f:
            content = f.read()
            
        original_content = content
        
        # 1. Replace mapped icons
        for emoji, svg in ICONS.items():
            content = content.replace(emoji, svg)
            
        # 2. Remove other emojis
        for emoji in REMOVE_LIST:
             content = content.replace(emoji, "")
             
        # 3. Add CSS for icons if not present
        if "/* SVG Icon Styles */" not in content:
            css = """
        /* SVG Icon Styles */
        svg.feature-icon {
            width: 1.5em;
            height: 1.5em;
            vertical-align: middle;
            margin-right: 0.5rem;
            display: inline-block;
        }
        """
            content = content.replace("</style>", css + "</style>")
            
        if content != original_content:
            print(f"Updating {filename}")
            with open(path, "w", encoding="utf-8") as f:
                f.write(content)
        else:
            print(f"No changes for {filename}")

if __name__ == "__main__":
    update_files()
